INSERT INTO task_module (
    task_id, branch, module_name, module_path, status, port, pid, pgid,
    log_file, build_log_file, swagger_url, error_message, keep_alive_until,
    created_at, started_at, finished_at, commit_sha, commit_info, commit_mr_iid
) VALUES (
    #{taskId}, #{branch}, #{moduleName}, #{modulePath}, #{status}, #{port}, #{pid}, #{pgid},
    #{logFile}, #{buildLogFile}, #{swaggerUrl}, #{errorMessage}, #{keepAliveUntil},
    #{createdAt}, #{startedAt}, #{finishedAt}, #{commitSha}, #{commitInfo}, #{commitMrIid}
)
